#include<bits/stdc++.h>
using namespace std;
const int maxn=1e5+5;
int n,k,a[maxn],b[maxn],h[maxn],c;
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>k;
	for(int i=1; i<=n; i++) {
		cin>>a[i];
	}
	for(int i=1; i<=n; i++) {
		if(!b[i]) {
			c=0;
			for(int j=i; !b[j]; j=a[j]) {
				b[j]=1;
				h[c++]=j;
			}
			for(int j=0; j<c; j++) {
				a[h[j]]=h[(j%c+k%c)%c];
			}
		}
	}
	for(int i=1; i<=n; i++) {
		b[a[i]]=i;
	}
	for(int i=1; i<=n; i++) {
		cout<<b[i]<<" ";
	}
	return 0;
}
